public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        long max_time = 0;
        if (edges.length > 0) {
            for (long[] edge : edges) {
                if (edge[2] > max_time) {
                    max_time = edge[2];
                }
            }
        }

        long low = 0, high = max_time, ans = max_time;

        while (low <= high) {
            long mid = (low + high) / 2;
            if (isValid(n, edges, mid, k)) {
                ans = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        return ans;
    }

    private static boolean isValid(long n, long[][] edges, long t, long k) {
        long[] parent = new long[(int) n];
        long[] rank = new long[(int) n];
        for (long i = 0; i < n; i++) {
            parent[i] = i;
            rank[i] = 1;
        }
        long count = n;
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long time = edge[2];
            if (time > t) {
                long rootU = find(parent, u);
                long rootV = find(parent, v);
                if (rootU != rootV) {
                    if (rank[rootU] > rank[rootV]) {
                        parent[rootV] = rootU;
                    } else {
                        parent[rootU] = rootV;
                        if (rank[rootU] == rank[rootV]) {
                            rank[rootV]++;
                        }
                    }
                    count--;
                }
            }
        }
        return count >= k;
    }

    private static long find(long[] parent, long u) {
        while (parent[u] != u) {
            parent[u] = parent[parent[u]]; // path compression
            u = parent[u];
        }
        return u;
    }
}
