public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        if (edges.length == 0) {
            return 0;
        }
        long max_time = 0;
        for (long[] edge : edges) {
            max_time = Math.max(max_time, edge[2]);
        }
        long low = 0;
        long high = max_time;
        long ans = max_time;
        while (low <= high) {
            long mid = (low + high) / 2;
            if (is_valid(n, edges, mid, k)) {
                ans = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return ans;
    }

    private static boolean is_valid(long n, long[][] edges, long t, long k) {
        int[] parent = new int[(int) n];
        int[] rank = new int[(int) n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
            rank[i] = 1;
        }
        int count = (int) n;
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long time = edge[2];
            if (time > t) {
                int root_u = find(parent, (int) u);
                int root_v = find(parent, (int) v);
                if (root_u != root_v) {
                    if (rank[root_u] > rank[root_v]) {
                        parent[root_v] = root_u;
                    } else {
                        parent[root_u] = root_v;
                        if (rank[root_u] == rank[root_v]) {
                            rank[root_v] += 1;
                        }
                    }
                    count--;
                }
            }
        }
        return count >= k;
    }

    private static int find(int[] parent, int x) {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]]; // path compression
            x = parent[x];
        }
        return x;
    }
}
